import { parseApiResponse, request } from './apiClient'
import {
  getStoredRefreshToken,
  getStoredToken,
  persistAuthResult,
} from './sessionService'

function normalizeAuthData(payload) {
  const data = payload?.data ?? null

  if (!data || typeof data !== 'object') {
    return data
  }

  const token = data.token || data.accessToken || data.jwt || null
  const refreshToken = data.refreshToken || data.token || data.jwt || null
  const user = data.user || data.a || data.profile || data

  return {
    ...data,
    token,
    refreshToken,
    user,
  }
}

export async function login(payload) {
  const response = await request('/auth/login', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
  })

  const apiResponse = await parseApiResponse(response)
  return {
    ...apiResponse,
    data: normalizeAuthData(apiResponse),
  }
}

export async function register(payload) {
  const response = await request('/auth/register', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
  })

  const apiResponse = await parseApiResponse(response)
  return {
    ...apiResponse,
    data: normalizeAuthData(apiResponse),
  }
}

export async function refreshAuthToken(token = getStoredRefreshToken()) {
  if (!token) {
    throw new Error('Khong co token de lam moi')
  }

  const response = await request('/auth/refresh', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ token }),
  })

  const apiResponse = await parseApiResponse(response)
  const normalized = {
    ...apiResponse,
    data: normalizeAuthData(apiResponse),
  }

  persistAuthResult(normalized)
  return normalized
}

export async function authFetch(path, init = {}) {
  const headers = new Headers(init.headers || {})
  const token = getStoredToken()

  if (token) {
    headers.set('Authorization', `Bearer ${token}`)
  }

  const response = await request(path, {
    ...init,
    headers,
  })

  if (response.status !== 401) {
    return response
  }

  const refreshed = await refreshAuthToken()
  const nextHeaders = new Headers(init.headers || {})
  const nextToken = refreshed?.data?.token || getStoredToken()

  if (nextToken) {
    nextHeaders.set('Authorization', `Bearer ${nextToken}`)
  }

  return request(path, {
    ...init,
    headers: nextHeaders,
  })
}

export async function getCurrentUserDetail() {
  const response = await authFetch('/auth/userdetail')
  const apiResponse = await parseApiResponse(response)
  return apiResponse?.data || null
}

import { parseApiResponse, request } from './apiClient'
import {
  clearAuth,
  getStoredRefreshToken,
  getStoredToken,
  persistAuthResult,
} from './sessionService'

let refreshPromise = null

async function shouldTryRefresh(response) {
  if (response.status === 401) return true
  if (response.status !== 403) return false

  const payload = await response.clone().json().catch(() => null)
  const message = String(payload?.message || '').toLowerCase()
  const code = Number(payload?.code)

  const tokenHint =
    message.includes('token') ||
    message.includes('expired') ||
    message.includes('unauth') ||
    code === 401 ||
    code === 403

  return tokenHint
}

async function refreshTokenSingleFlight() {
  if (!refreshPromise) {
    refreshPromise = refreshAuthToken().finally(() => {
      refreshPromise = null
    })
  }

  return refreshPromise
}

function normalizeAuthData(payload) {
  const data = payload?.data ?? null

  if (!data || typeof data !== 'object') {
    return data
  }

  const token = data.token || data.accessToken || data.jwt || null
  const refreshToken = data.refreshToken || data.token || data.jwt || null
  const user = data.user || data.a || data.profile || data

  return {
    ...data,
    token,
    refreshToken,
    user,
  }
}

export async function login(payload) {
  const response = await request('/auth/login', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
  })

  const apiResponse = await parseApiResponse(response)
  return {
    ...apiResponse,
    data: normalizeAuthData(apiResponse),
  }
}

export async function register(payload) {
  const response = await request('/auth/register', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
  })

  const apiResponse = await parseApiResponse(response)
  return {
    ...apiResponse,
    data: normalizeAuthData(apiResponse),
  }
}

export async function refreshAuthToken(token = getStoredRefreshToken()) {
  if (!token) {
    throw new Error('Khong co token de lam moi')
  }

  const response = await request('/auth/refresh', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ token }),
  })

  const apiResponse = await parseApiResponse(response)
  const normalized = {
    ...apiResponse,
    data: normalizeAuthData(apiResponse),
  }

  persistAuthResult(normalized)
  return normalized
}

export async function authFetch(path, init = {}) {
  const headers = new Headers(init.headers || {})
  const token = getStoredToken()

  if (token) {
    headers.set('Authorization', `Bearer ${token}`)
  }

  const response = await request(path, {
    ...init,
    headers,
  })

  const canRefresh = await shouldTryRefresh(response)
  if (!canRefresh) {
    return response
  }

  try {
    const refreshed = await refreshTokenSingleFlight()
    const nextHeaders = new Headers(init.headers || {})
    const nextToken = refreshed?.data?.token || getStoredToken()

    if (nextToken) {
      nextHeaders.set('Authorization', `Bearer ${nextToken}`)
    }

    return request(path, {
      ...init,
      headers: nextHeaders,
    })
  } catch (error) {
    clearAuth()
    throw error
  }
}

export async function getCurrentUserDetail() {
  try {
    const response = await authFetch('/auth/userdetail')
    const apiResponse = await parseApiResponse(response)
    return apiResponse?.data || null
  } catch (firstError) {
    await refreshTokenSingleFlight()

    const retried = await authFetch('/auth/userdetail')
    const retryPayload = await parseApiResponse(retried)
    return retryPayload?.data || null
  }
}

const AUTH_KEY = 'splitgo_auth'
const TOKEN_KEY = 'splitgo_token'
const REFRESH_TOKEN_KEY = 'splitgo_refresh_token'

export function getStoredAuth() {
  const raw = localStorage.getItem(AUTH_KEY)
  if (!raw) return null

  try {
    return JSON.parse(raw)
  } catch {
    return null
  }
}

export function getStoredToken() {
  return localStorage.getItem(TOKEN_KEY) || ''
}

export function getStoredRefreshToken() {
  return localStorage.getItem(REFRESH_TOKEN_KEY) || getStoredToken()
}

export function clearAuth() {
  localStorage.removeItem(AUTH_KEY)
  localStorage.removeItem(TOKEN_KEY)
  localStorage.removeItem(REFRESH_TOKEN_KEY)
}

export function persistAuthResult(payload) {
  if (!payload?.data) return

  const authData = payload.data
  localStorage.setItem(AUTH_KEY, JSON.stringify(authData))

  if (authData.token) {
    localStorage.setItem(TOKEN_KEY, authData.token)
    localStorage.setItem(REFRESH_TOKEN_KEY, authData.refreshToken || authData.token)
  }
}

export function getAuthSession() {
  const token = getStoredToken()
  if (!token) return null

  const auth = getStoredAuth() || {}
  return {
    ...auth,
    token,
    user: auth.user || auth.a || auth,
  }
}

const AUTH_KEY = 'splitgo_auth'
const TOKEN_KEY = 'splitgo_token'
const REFRESH_TOKEN_KEY = 'splitgo_refresh_token'

export function getStoredAuth() {
  const raw = localStorage.getItem(AUTH_KEY)
  if (!raw) return null

  try {
    return JSON.parse(raw)
  } catch {
    return null
  }
}

export function getStoredToken() {
  return localStorage.getItem(TOKEN_KEY) || ''
}

export function getStoredRefreshToken() {
  return localStorage.getItem(REFRESH_TOKEN_KEY) || getStoredToken()
}

export function clearAuth() {
  localStorage.removeItem(AUTH_KEY)
  localStorage.removeItem(TOKEN_KEY)
  localStorage.removeItem(REFRESH_TOKEN_KEY)
}

export function persistAuthResult(payload) {
  if (!payload?.data) return

  const previous = getStoredAuth() || {}
  const authData = {
    ...previous,
    ...payload.data,
  }

  if (!authData.user && previous.user) {
    authData.user = previous.user
  }

  localStorage.setItem(AUTH_KEY, JSON.stringify(authData))

  if (authData.token) {
    localStorage.setItem(TOKEN_KEY, authData.token)
    localStorage.setItem(REFRESH_TOKEN_KEY, authData.refreshToken || authData.token)
  }
}

export function getAuthSession() {
  const token = getStoredToken()
  if (!token) return null

  const auth = getStoredAuth() || {}
  return {
    ...auth,
    token,
    user: auth.user || auth.a || auth,
  }
}
